package value

import (
	"bytes"
	"context"
	"fmt"
	"testing"

	genericapirequest "k8s.io/apiserver/pkg/endpoints/request"
)

// mockTransformer is a simple mock implementation of the Transformer interface
type mockTransformer struct {
	transformFromStorageFunc func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error)
	transformToStorageFunc   func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error)
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	if m.transformFromStorageFunc != nil {
		return m.transformFromStorageFunc(ctx, data, dataCtx)
	}
	return data, false, nil
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	if m.transformToStorageFunc != nil {
		return m.transformToStorageFunc(ctx, data, dataCtx)
	}
	return data, nil
}

// TestDefaultContextAuthenticatedData tests that DefaultContext correctly implements
// the Context interface by returning its bytes as authenticated data.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	testCases := []struct {
		name     string
		data     []byte
		expected []byte
	}{
		{
			name:     "non-empty bytes",
			data:     []byte("test-data"),
			expected: []byte("test-data"),
		},
		{
			name:     "empty bytes",
			data:     []byte{},
			expected: []byte{},
		},
		{
			name:     "nil bytes",
			data:     nil,
			expected: nil,
		},
		{
			name:     "binary data",
			data:     []byte{0, 1, 2, 3, 4, 5},
			expected: []byte{0, 1, 2, 3, 4, 5},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := DefaultContext(tc.data)
			result := ctx.AuthenticatedData()
			if !bytes.Equal(result, tc.expected) {
				t.Errorf("expected %v, got %v", tc.expected, result)
			}
		})
	}
}

// TestTransformerRoundTrip tests that a value can be transformed to storage and back.
func TestTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name           string
		originalData   []byte
		transformedTo  []byte
		transformedFrom []byte
		transformErr   error
	}{
		{
			name:           "simple round-trip",
			originalData:   []byte("original"),
			transformedTo:  []byte("encrypted"),
			transformedFrom: []byte("original"),
		},
		{
			name:           "empty data",
			originalData:   []byte{},
			transformedTo:  []byte("encrypted-empty"),
			transformedFrom: []byte{},
		},
		{
			name:           "large data",
			originalData:   bytes.Repeat([]byte("x"), 1000),
			transformedTo:  []byte("encrypted-large"),
			transformedFrom: bytes.Repeat([]byte("x"), 1000),
		},
		{
			name:           "binary data",
			originalData:   []byte{0, 1, 2, 3, 255, 254, 253},
			transformedTo:  []byte("encrypted-binary"),
			transformedFrom: []byte{0, 1, 2, 3, 255, 254, 253},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			dataCtx := DefaultContext([]byte("auth-data"))

			transformer := &mockTransformer{
				transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
					if !bytes.Equal(data, tc.originalData) {
						return nil, fmt.Errorf("expected %v, got %v", tc.originalData, data)
					}
					return tc.transformedTo, nil
				},
				transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
					if !bytes.Equal(data, tc.transformedTo) {
						return nil, false, fmt.Errorf("expected %v, got %v", tc.transformedTo, data)
					}
					return tc.transformedFrom, false, nil
				},
			}

			// Transform to storage
			encrypted, err := transformer.TransformToStorage(ctx, tc.originalData, dataCtx)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			// Transform from storage
			decrypted, _, err := transformer.TransformFromStorage(ctx, encrypted, dataCtx)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			// Verify round-trip
			if !bytes.Equal(decrypted, tc.originalData) {
				t.Errorf("round-trip failed: expected %v, got %v", tc.originalData, decrypted)
			}
		})
	}
}

// TestPrefixTransformerRoundTrip tests that PrefixTransformer correctly adds
// and removes prefixes during transformation.
func TestPrefixTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name           string
		prefix         []byte
		data           []byte
		expectedOutput []byte
	}{
		{
			name:           "simple prefix",
			prefix:         []byte("prefix:"),
			data:           []byte("data"),
			expectedOutput: []byte("data"),
		},
		{
			name:           "empty prefix",
			prefix:         []byte{},
			data:           []byte("data"),
			expectedOutput: []byte("data"),
		},
		{
			name:           "binary prefix",
			prefix:         []byte{0, 1, 2},
			data:           []byte("data"),
			expectedOutput: []byte("data"),
		},
		{
			name:           "long prefix",
			prefix:         []byte("k8s:enc:aescbc:v1:"),
			data:           []byte("sensitive-data"),
			expectedOutput: []byte("sensitive-data"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
			dataCtx := DefaultContext([]byte("auth"))

			innerTransformer := &mockTransformer{
				transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
					return data, nil
				},
				transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
					return data, false, nil
				},
			}

			prefixedTransformer := NewPrefixTransformers(fmt.Errorf("default error"),
				PrefixTransformer{
					Prefix:      tc.prefix,
					Transformer: innerTransformer,
				},
			)

			// TransformToStorage should add prefix
			encrypted, err := prefixedTransformer.TransformToStorage(ctx, tc.data, dataCtx)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			// Verify prefix was added
			if !bytes.HasPrefix(encrypted, tc.prefix) {
				t.Errorf("expected prefix %v to be present in %v", tc.prefix, encrypted)
			}

			// Verify data is after prefix
			expectedData := append(tc.prefix, tc.data...)
			if !bytes.Equal(encrypted, expectedData) {
				t.Errorf("expected %v, got %v", expectedData, encrypted)
			}

			// TransformFromStorage should strip prefix
			decrypted, _, err := prefixedTransformer.TransformFromStorage(ctx, encrypted, dataCtx)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			// Verify data matches
			if !bytes.Equal(decrypted, tc.expectedOutput) {
				t.Errorf("expected %v, got %v", tc.expectedOutput, decrypted)
			}
		})
	}
}

// TestPrefixTransformerMismatchedPrefix tests that PrefixTransformer returns
// an error when the data prefix does not match any transformer.
func TestPrefixTransformerMismatchedPrefix(t *testing.T) {
	testErr := fmt.Errorf("no matching transformer")

	transformer := &mockTransformer{}
	prefixedTransformer := NewPrefixTransformers(testErr,
		PrefixTransformer{
			Prefix:      []byte("expected:"),
			Transformer: transformer,
		},
	)

	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
	dataCtx := DefaultContext([]byte("auth"))

	// Try to transform data with mismatched prefix
	_, _, err := prefixedTransformer.TransformFromStorage(ctx, []byte("wrong:data"), dataCtx)
	if err == nil {
		t.Fatal("expected error for mismatched prefix, got nil")
	}

	if err != testErr {
		t.Errorf("expected error %v, got %v", testErr, err)
	}
}

// TestMultiplePrefixTransformersSelection tests that the correct transformer
// is selected based on prefix matching.
func TestMultiplePrefixTransformersSelection(t *testing.T) {
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
	dataCtx := DefaultContext([]byte("auth"))

	transformer1Called := false
	transformer2Called := false
	transformer3Called := false

	transformer1 := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			transformer1Called = true
			return []byte("result1"), false, nil
		},
	}

	transformer2 := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			transformer2Called = true
			return []byte("result2"), false, nil
		},
	}

	transformer3 := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			transformer3Called = true
			return []byte("result3"), false, nil
		},
	}

	prefixedTransformer := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: transformer1},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: transformer2},
		PrefixTransformer{Prefix: []byte("third:"), Transformer: transformer3},
	)

	testCases := []struct {
		name      string
		input     []byte
		expected  []byte
		shouldUse func() bool
	}{
		{
			name:      "first transformer",
			input:     []byte("first:data"),
			expected:  []byte("result1"),
			shouldUse: func() bool { return transformer1Called },
		},
		{
			name:      "second transformer",
			input:     []byte("second:data"),
			expected:  []byte("result2"),
			shouldUse: func() bool { return transformer2Called },
		},
		{
			name:      "third transformer",
			input:     []byte("third:data"),
			expected:  []byte("result3"),
			shouldUse: func() bool { return transformer3Called },
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Reset flags
			transformer1Called = false
			transformer2Called = false
			transformer3Called = false

			result, _, err := prefixedTransformer.TransformFromStorage(ctx, tc.input, dataCtx)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if !bytes.Equal(result, tc.expected) {
				t.Errorf("expected %v, got %v", tc.expected, result)
			}

			if !tc.shouldUse() {
				t.Error("expected transformer to be called, but it was not")
			}
		})
	}
}

// TestStaleDataMarking tests that non-first transformers mark data as stale.
func TestStaleDataMarking(t *testing.T) {
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
	dataCtx := DefaultContext([]byte("auth"))

	transformer1 := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return []byte("result"), false, nil
		},
	}

	transformer2 := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return []byte("result"), false, nil
		},
	}

	prefixedTransformer := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: transformer1},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: transformer2},
	)

	testCases := []struct {
		name          string
		input         []byte
		expectedStale bool
	}{
		{
			name:          "first transformer not stale",
			input:         []byte("first:data"),
			expectedStale: false,
		},
		{
			name:          "second transformer marked stale",
			input:         []byte("second:data"),
			expectedStale: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			_, stale, err := prefixedTransformer.TransformFromStorage(ctx, tc.input, dataCtx)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			if stale != tc.expectedStale {
				t.Errorf("expected stale=%v, got stale=%v", tc.expectedStale, stale)
			}
		})
	}
}

// TestTransformerErrorPropagation tests that errors from transformers are properly propagated.
func TestTransformerErrorPropagation(t *testing.T) {
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
	dataCtx := DefaultContext([]byte("auth"))

	transformErr := fmt.Errorf("transformation failed")

	failingTransformer := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			return nil, transformErr
		},
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return nil, false, transformErr
		},
	}

	prefixedTransformer := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("prefix:"), Transformer: failingTransformer},
	)

	// Test TransformToStorage error propagation
	_, err := prefixedTransformer.TransformToStorage(ctx, []byte("data"), dataCtx)
	if err == nil {
		t.Fatal("expected error from TransformToStorage, got nil")
	}
	if err != transformErr {
		t.Errorf("expected error %v, got %v", transformErr, err)
	}

	// Test TransformFromStorage error propagation
	_, _, err = prefixedTransformer.TransformFromStorage(ctx, []byte("prefix:data"), dataCtx)
	if err == nil {
		t.Fatal("expected error from TransformFromStorage, got nil")
	}
	if err != transformErr {
		t.Errorf("expected error %v, got %v", transformErr, err)
	}
}

// TestContextInterfaceImplementation tests that custom Context implementations work correctly.
func TestContextInterfaceImplementation(t *testing.T) {
	// Custom context implementation
	customContext := DefaultContext([]byte("custom-auth-data"))

	expectedAuth := []byte("custom-auth-data")
	result := customContext.AuthenticatedData()

	if !bytes.Equal(result, expectedAuth) {
		t.Errorf("expected %v, got %v", expectedAuth, result)
	}

	// Test with transformer
	ctx := context.Background()
	dataCtx := customContext

	receivedContext := false
	transformer := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			if dataCtx != nil && bytes.Equal(dataCtx.AuthenticatedData(), expectedAuth) {
				receivedContext = true
			}
			return data, nil
		},
	}

	_, _ = transformer.TransformToStorage(ctx, []byte("data"), dataCtx)
	if !receivedContext {
		t.Error("transformer did not receive expected context")
	}
}

// TestNilContextHandling tests that transformers can handle nil context.
func TestNilContextHandling(t *testing.T) {
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})

	transformer := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			return data, nil
		},
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return data, false, nil
		},
	}

	prefixedTransformer := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("prefix:"), Transformer: transformer},
	)

	// TransformToStorage with nil context
	result, err := prefixedTransformer.TransformToStorage(ctx, []byte("data"), nil)
	if err != nil {
		t.Fatalf("TransformToStorage failed with nil context: %v", err)
	}
	if !bytes.Equal(result, []byte("prefix:data")) {
		t.Errorf("expected %v, got %v", []byte("prefix:data"), result)
	}

	// TransformFromStorage with nil context
	result, _, err = prefixedTransformer.TransformFromStorage(ctx, []byte("prefix:data"), nil)
	if err != nil {
		t.Fatalf("TransformFromStorage failed with nil context: %v", err)
	}
	if !bytes.Equal(result, []byte("data")) {
		t.Errorf("expected %v, got %v", []byte("data"), result)
	}
}

// TestEmptyDataTransformation tests transformation of empty data.
func TestEmptyDataTransformation(t *testing.T) {
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
	dataCtx := DefaultContext([]byte("auth"))

	transformer := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			return data, nil
		},
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return data, false, nil
		},
	}

	prefixedTransformer := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("prefix:"), Transformer: transformer},
	)

	// Transform empty data to storage
	encrypted, err := prefixedTransformer.TransformToStorage(ctx, []byte{}, dataCtx)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	// Should contain only the prefix
	if !bytes.Equal(encrypted, []byte("prefix:")) {
		t.Errorf("expected %v, got %v", []byte("prefix:"), encrypted)
	}

	// Transform empty encrypted data from storage
	decrypted, _, err := prefixedTransformer.TransformFromStorage(ctx, encrypted, dataCtx)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}

	// Should be empty
	if len(decrypted) != 0 {
		t.Errorf("expected empty data, got %v", decrypted)
	}
}

// TestTransformerUsageOfFirstTransformer tests that TransformToStorage always uses
// the first transformer regardless of data prefix.
func TestTransformerUsageOfFirstTransformer(t *testing.T) {
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
	dataCtx := DefaultContext([]byte("auth"))

	firstUsed := false
	secondUsed := false

	transformer1 := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			firstUsed = true
			return []byte("encrypted-by-first"), nil
		},
	}

	transformer2 := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			secondUsed = true
			return []byte("encrypted-by-second"), nil
		},
	}

	prefixedTransformer := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: transformer1},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: transformer2},
	)

	result, err := prefixedTransformer.TransformToStorage(ctx, []byte("data"), dataCtx)
	if err != nil {
		t.Fatalf("TransformToStorage failed: %v", err)
	}

	if !firstUsed {
		t.Error("expected first transformer to be used")
	}

	if secondUsed {
		t.Error("expected second transformer not to be used")
	}

	if !bytes.Equal(result, []byte("first:encrypted-by-first")) {
		t.Errorf("expected %v, got %v", []byte("first:encrypted-by-first"), result)
	}
}

// TestOverlappingPrefixesFallback tests that when a transformer with a prefix fails,
// fallback to the next transformer with the same or overlapping prefix works.
func TestOverlappingPrefixesFallback(t *testing.T) {
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
	dataCtx := DefaultContext([]byte("auth"))

	sharedPrefix := []byte("enc:")
	failErr := fmt.Errorf("first transformer failed")

	failingTransformer := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return nil, false, failErr
		},
	}

	fallbackTransformer := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			return []byte("recovered"), false, nil
		},
	}

	prefixedTransformer := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: sharedPrefix, Transformer: failingTransformer},
		PrefixTransformer{Prefix: []byte("enc:v2:"), Transformer: fallbackTransformer},
	)

	// Data with the shared prefix should try first transformer, fail, then try second
	result, _, err := prefixedTransformer.TransformFromStorage(ctx, []byte("enc:v2:data"), dataCtx)
	if err != nil {
		t.Fatalf("TransformFromStorage failed: %v", err)
	}

	if !bytes.Equal(result, []byte("recovered")) {
		t.Errorf("expected %v, got %v", []byte("recovered"), result)
	}
}

