// mockTransformer is a simple mock implementation of the Transformer interface
type mockTransformer struct {
	transformFromStorageFunc func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error)
	transformToStorageFunc   func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error)
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	if m.transformFromStorageFunc != nil {
		return m.transformFromStorageFunc(ctx, data, dataCtx)
	}
	return data, false, nil
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	if m.transformToStorageFunc != nil {
		return m.transformToStorageFunc(ctx, data, dataCtx)
	}
	return data, nil
}

// TestDefaultContextAuthenticatedData tests that DefaultContext correctly implements
// the Context interface by returning its bytes as authenticated data.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	testCases := []struct {
		name     string
		data     []byte
		expected []byte
	}{
		{
			name:     "non-empty bytes",
			data:     []byte("test-data"),
			expected: []byte("test-data"),
		},
		{
			name:     "empty bytes",
			data:     []byte{},
			expected: []byte{},
		},
		{
			name:     "nil bytes",
			data:     nil,
			expected: nil,
		},
		{
			name:     "binary data",
			data:     []byte{0, 1, 2, 3, 4, 5},
			expected: []byte{0, 1, 2, 3, 4, 5},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := DefaultContext(tc.data)
			result := ctx.AuthenticatedData()
			if !bytes.Equal(result, tc.expected) {
				t.Errorf("expected %v, got %v", tc.expected, result)
			}
		})
	}
}

// TestTransformerRoundTrip tests that a value can be transformed to storage and back.
func TestTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name           string
		originalData   []byte
		transformedTo  []byte
		transformedFrom []byte
		transformErr   error
	}{
		{
			name:           "simple round-trip",
			originalData:   []byte("original"),
			transformedTo:  []byte("encrypted"),
			transformedFrom: []byte("original"),
		},
		{
			name:           "empty data",
			originalData:   []byte{},
			transformedTo:  []byte("encrypted-empty"),
			transformedFrom: []byte{},
		},
		{
			name:           "large data",
			originalData:   bytes.Repeat([]byte("x"), 1000),
			transformedTo:  []byte("encrypted-large"),
			transformedFrom: bytes.Repeat([]byte("x"), 1000),
		},
		{
			name:           "binary data",
			originalData:   []byte{0, 1, 2, 3, 255, 254, 253},
			transformedTo:  []byte("encrypted-binary"),
			transformedFrom: []byte{0, 1, 2, 3, 255, 254, 253},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			dataCtx := DefaultContext([]byte("auth-data"))

			transformer := &mockTransformer{
				transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
					if !bytes.Equal(data, tc.originalData) {
						return nil, fmt.Errorf("expected %v, got %v", tc.originalData, data)
					}
					return tc.transformedTo, nil
				},
				transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
					if !bytes.Equal(data, tc.transformedTo) {
						return nil, false, fmt.Errorf("expected %v, got %v", tc.transformedTo, data)
					}
					return tc.transformedFrom, false, nil
				},
			}

			// Transform to storage
			encrypted, err := transformer.TransformToStorage(ctx, tc.originalData, dataCtx)
			if err != nil {
				t.Fatalf("TransformToStorage failed: %v", err)
			}

			// Transform from storage
			decrypted, _, err := transformer.TransformFromStorage(ctx, encrypted, dataCtx)
			if err != nil {
				t.Fatalf("TransformFromStorage failed: %v", err)
			}

			// Verify round-trip
			if !bytes.Equal(decrypted, tc.originalData) {
				t.Errorf("round-trip failed: expected %v, got %v", tc.originalData, decrypted)
			}
		})
	}
}

// TestPrefixTransformerRoundTrip tests that PrefixTransformer correctly adds
// and removes prefixes during transformation.
func TestPrefixTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name           string
		prefix         []byte
		data           []byte
		expectedOutput []byte
	}{
		{
			name:           "simple prefix",
			prefix:         []byte("prefix:"),
			data:           []byte("data"),
			expectedOutput: []byte("data"),
		},
		{
			name:           "empty prefix",
			prefix:         []byte{},
			data:           []byte("data"),
			expectedOutput: []byte("data"),
		},
		{
			name:           "binary prefix",
			prefix:         []byte{0, 1, 2},
			data:           []byte("data"),
			expectedOutput: []byte("data"),
		},
		{
			name:           "long prefix",
			prefix:         []byte("k8s:enc:aescbc:v1:"),
			data:           []byte("sensitive-data"),
			expectedOutput: []byte("sensitive-data"),
