	transformer1 := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			transformer1Called = true
			return []byte("result1"), false, nil
		},
	}

	transformer2 := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			transformer2Called = true
			return []byte("result2"), false, nil
		},
	}

	transformer3 := &mockTransformer{
		transformFromStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
			transformer3Called = true
			return []byte("result3"), false, nil
		},
	}

	prefixedTransformer := NewPrefixTransformers(fmt.Errorf("no match"),
		PrefixTransformer{Prefix: []byte("first:"), Transformer: transformer1},
		PrefixTransformer{Prefix: []byte("second:"), Transformer: transformer2},
		PrefixTransformer{Prefix: []byte("third:"), Transformer: transformer3},
	)

	testCases := []struct {
		name      string
		input     []byte
		expected  []byte
		shouldUse func() bool
	}{
		{
			name:      "first transformer",
			input:     []byte("first:data"),
			expected:  []byte("result1"),
			shouldUse: func() bool { return transformer1Called },
		},
		{
			name:      "second transformer",
			input:     []byte("second:data"),
			expected:  []byte("result2"),
			shouldUse: func() bool { return transformer2Called },
		},
