// TestTransformerUsageOfFirstTransformer tests that TransformToStorage always uses
// the first transformer regardless of data prefix.
func TestTransformerUsageOfFirstTransformer(t *testing.T) {
	ctx := genericapirequest.WithRequestInfo(context.Background(), &genericapirequest.RequestInfo{Resource: "test"})
	dataCtx := DefaultContext([]byte("auth"))

	firstUsed := false
	secondUsed := false

	transformer1 := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			firstUsed = true
			return []byte("encrypted-by-first"), nil
		},
	}

	transformer2 := &mockTransformer{
		transformToStorageFunc: func(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
			secondUsed = true
			return []byte("encrypted-by-second"), nil
		},
	}

	prefixedTransformer := NewPrefixTransformers(fmt.Errorf("no match"),
